      enable = true;
      libraries = with pkgs; [
        stdenv.cc.cc.lib
        zlib
        libgcc.lib
        libxcrypt-legacy
        openssl.out
        fuse3
        icu
        nss
        curl
        expat
        # GPU / Graphics
        libvdpau
        libva
        vulkan-loader
        libGL
        egl-wayland
        wayland
        libxkbcommon
        linuxPackages.nvidia_x11.out
        cudaPackages.cuda_cudart
        cudaPackages.libcublas
        cudaPackages.nccl
        libglvnd
        mesa
